        private static string MaskPotentiallyInBodyData(string body)
        {
            var sensitivePatterns = new[]
            {
                @"(password|pwd|secret|token|key|apikey|api_key)(\s*[:=]\s*)(['""]?)([^'""}\s,]+)",
                @"(authorization|bearer)(\s*[:=]\s*)(['""]?)([^'""}\s,]+)",
                @"(\d{13,19})",
